import axios from 'axios';

// 创建axios实例
const api = axios.create({
  baseURL: 'http://localhost:8080/api',  // 后端API地址
  timeout: 10000,  // 请求超时时间
  headers: {
    'Content-Type': 'application/json',
    'Accept': 'application/json'
  }
});

// 请求拦截器
api.interceptors.request.use(
  config => {
    // 从localStorage获取token
    const userStr = localStorage.getItem('user');
    if (userStr) {
      try {
        const user = JSON.parse(userStr);
        // 支持多种token字段名
        const token = user.token || user.accessToken;
        if (token) {
          // 在请求头中添加token
          config.headers['Authorization'] = `Bearer ${token}`;
          console.log('已添加认证头:', `Bearer ${token.substring(0, 10)}...`);
        } else {
          console.warn('用户信息中没有token字段');
        }
      } catch (e) {
        console.error('解析用户信息失败:', e);
      }
    } else {
      console.warn('localStorage中没有用户信息');
    }
    return config;
  },
  error => {
    console.error('请求错误:', error);
    return Promise.reject(error);
  }
);

// 响应拦截器
api.interceptors.response.use(
  response => {
    return response;
  },
  error => {
    console.error('响应错误:', error.response || error);

    // 处理401错误 - 未认证
    if (error.response && error.response.status === 401) {
      console.warn('收到401未授权响应，清除用户信息');
      localStorage.removeItem('user');

      // 如果不是在登录页，则重定向到登录页
      if (window.location.pathname !== '/login') {
        window.location.href = '/login?redirect=' + encodeURIComponent(window.location.pathname);
      }
    }

    return Promise.reject(error);
  }
);

export default api;
